mapper.select:
select policy_id, policy_name, version, phase, status, del_deadline, del_deadline_unit, archive_flag, arc_del_deadline, arc_del_deadline_unit, related_law, comments, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
  from cotdl.tbl_piipolicy a 
 where upper(policy_id) = upper(#{policy_id, jdbcType=VARCHAR}) and version= #{version, jdbcType=VARCHAR}

 
		 
		select 
			   policy_id, policy_name, version, phase, status, del_deadline, del_deadline_unit, archive_flag, arc_del_deadline, arc_del_deadline_unit, related_law, comments, regdate, upddate, reguserid, upduserid
		from ( 
				select 
					 ROWNUM rn, policy_id, policy_name, version, phase, status, del_deadline, del_deadline_unit, archive_flag, arc_del_deadline, arc_del_deadline_unit, related_law, comments, regdate, upddate, reguserid, upduserid 
				from (
						select policy_id, policy_name, version, phase, status, del_deadline, del_deadline_unit, archive_flag, arc_del_deadline, arc_del_deadline_unit, related_law, comments, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piipolicy a 
						 where 1=1 
						   and version in (select max(to_number(version)) from cotdl.tbl_piipolicy where policy_id = a.policy_id)
						 order by policy_id 
					 ) f
				where 
		
	    
		
						
							upper(policy_id) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and policy_name = #{search2}
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by policy_id
			  ) k
		where rn > (#{pagenum} -1) * #{amount} 
		order by policy_id
